      END_STATE();
    case 62:
      ACCEPT_TOKEN(anon_sym_super);
      END_STATE();
    case 63:
      ACCEPT_TOKEN(anon_sym_trait);
      END_STATE();
    case 64:
      ACCEPT_TOKEN(anon_sym_struct);
      END_STATE();
    default:
